 * Key: two-pointer-lag idiom (p = lagging copy read via v0, s = live cursor)
 * + guard + do-while; loop statement order p=s; s++; n++ sets the
 * addiu a0 / addiu v1 order; bnezl delay slot = p=s. */
int game_libs_func_00067FA4(char *s) {
    int n = 0;
    char *p;

    p = s;
    s++;
    if (*p != 0) {
        do {
            p = s;
            s++;
            n++;
        } while (*p != 0);
    }
    return n;
}
